-	lineNo := 0
-
-	for scanner.Scan() {
-		lineNo++
-		line := scanner.Text()
-		if strings.TrimSpace(line) == "" {
-			continue
-		}
-
-		// Skip Git merge conflict markers
-		trimmed := strings.TrimSpace(line)
-		if strings.HasPrefix(trimmed, "<<<<<<< ") ||
