-				Line:    lineNo,
-				Message: err.Error(),
-				Snippet: truncateSnippet(line, 50),
-			})
-			continue
-		}
-
-		// Apply defaults for omitted fields
-		issue.SetDefaults()
-
-		// Fix closed_at invariant
-		if issue.Status == types.StatusClosed && issue.ClosedAt == nil {
-			now := time.Now()
